import {{ Injectable }} from '@nestjs/common';
import {{ SearchService }} from './models/search.model';
import {{ SearchServiceRepository }} from './repositories/search.repository';

@Injectable()
export class SearchServiceService {{
  constructor(
    private readonly repository: SearchServiceRepository,
  ) {{}}

  async findAll(): Promise<SearchService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<SearchService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<SearchService>): Promise<SearchService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<SearchService>): Promise<SearchService> {{
    return this.repository.update(id, data);
  }}
}}
